for biz_ref, data in biz_ratings.items():
    state = data['state']
    if data['ratings']:
        avg_rating = sum(data['ratings']) / len(data['ratings'])
        if state not in state_ratings:
            state_ratings[state] = []
        state_ratings[state].append(avg_rating)

# Calculate overall average per state
state_avg_ratings = {}
for state, ratings in state_ratings.items():
    state_avg_ratings[state] = sum(ratings) / len(ratings)

# Find state with highest number of WiFi businesses
if state_counts:
    sorted_states = sorted(state_counts.items(), key=lambda x: x[1], reverse=True)
    top_state_name = sorted_states[0][0]
    top_state_count = sorted_states[0][1]
    top_state_avg_rating = state_avg_ratings.get(top_state_name, 'N/A')
else:
