            state_match = re.search(r',\s*([A-Z]{2})\b', desc)
            if state_match:
                state = state_match.group(1)
                wifi_with_states.append({
                    'business_id': biz['business_id'],
                    'name': biz['name'],
                    'state': state,
                    'wifi': wifi_val
                })

# Count by state
from collections import Counter
state_counts = Counter([biz['state'] for biz in wifi_with_states])

# Load ratings from user database
reviews = locals()['var_functions.query_db:14']

# Map business_id to state and collect ratings
biz_ratings = {}
for biz in wifi_with_states:
